SELECT data_content 
FROM report_data 
WHERE report_id = 1;

SELECT authority_name, region, SIN(median_income) AS sine_of_median_income
FROM local_authorities
WHERE region = 'London';

SELECT *
FROM reporting
WHERE report_id < 2 AND last_updated > '2023-04-01';

SELECT authority_name
FROM local_authorities
WHERE authority_code = '0';

SELECT msoa_code, MAX(house_price) AS max_price
FROM property_sales
GROUP BY msoa_code;

SELECT ps.transaction_type, ps.msoa_code, AVG(ps.house_price) AS average_house_price
FROM property_sales ps
GROUP BY ps.transaction_type, ps.msoa_code;

SELECT AVG(population) AS AvgPopulation
FROM local_authorities
WHERE area_sq_km > 100;
